try {
  const BRT_MS = 3 * 3600 * 1000;
  const utcNow = new Date();
  const brNow = new Date(utcNow.getTime() - BRT_MS);
  let busyPeriods = [];
  try {
    const calData = $input.first().json;
    busyPeriods = calData.calendars?.primary?.busy || [];
  } catch(e) {}
  const busy = busyPeriods.map(b => ({ startUtc: new Date(b.start).getTime(), endUtc: new Date(b.end).getTime() }));
  const dayNames = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const pad = n => String(n).padStart(2, '0');
  const busyText = busy.length > 0 ? busy.map(b => { const startBr = new Date(b.startUtc - BRT_MS); const endBr = new Date(b.endUtc - BRT_MS); return dayNames[startBr.getUTCDay()] + ' ' + pad(startBr.getUTCDate()) + '/' + pad(startBr.getUTCMonth()+1) + ' ' + pad(startBr.getUTCHours()) + ':' + pad(startBr.getUTCMinutes()) + '-' + pad(endBr.getUTCHours()) + ':' + pad(endBr.getUTCMinutes()); }).join(', ') : 'nenhum compromisso agendado esta semana';
  const freeSlots = [];
  for (let d = 0; d < 7 && freeSlots.length < 6; d++) {
    const dayBr = new Date(brNow);
    dayBr.setUTCDate(dayBr.getUTCDate() + d);
    const wday = dayBr.getUTCDay();
    if (wday === 0) continue;
    const dayLabel = dayNames[wday] + ' ' + pad(dayBr.getUTCDate()) + '/' + pad(dayBr.getUTCMonth()+1);
    for (let h = 8; h <= 22; h++) {
      for (const m of [0, 30]) {
        if (freeSlots.length >= 6) break;
        const slotBr = new Date(dayBr);
        slotBr.setUTCHours(h, m, 0, 0);
        const slotUtcStart = slotBr.getTime() + BRT_MS;
        const slotUtcEnd = slotUtcStart + 30 * 60 * 1000;
        if (slotUtcStart <= utcNow.getTime()) continue;
        const isBusy = busy.some(b => slotUtcStart < b.endUtc && slotUtcEnd > b.startUtc);
        if (!isBusy) freeSlots.push(dayLabel + ' ' + pad(h) + ':' + pad(m));
      }
    }
  }
  const nextSlotsText = freeSlots.slice(0, 4).join(', ') || 'próximos dias úteis';
  return [{ json: { busyText, nextSlotsText, totalBusy: busy.length } }];
} catch(e) {
  return [{ json: { busyText: 'nenhum compromisso', nextSlotsText: 'dias úteis 8h-22h', totalBusy: 0 } }];
}

const BRT_MS = 3 * 3600 * 1000;
